let AIDomains = dynamic(["openai.com", "chatgpt.com", "api.openai.com", "anthropic.com", "api.anthropic.com", "claude.ai", "gemini.google.com", "generativelanguage.googleapis.com", "makersuite.google.com", "cohere.ai", "api.cohere.ai", "mistral.ai", "api.mistral.ai", "perplexity.ai", "api.perplexity.ai", "huggingface.co", "api-inference.huggingface.co", "replicate.com", "api.replicate.com", "together.ai", "together.xyz", "fireworks.ai", "stability.ai", "grok.com", "x.ai"]);
let SharePointDownloads =
    OfficeActivity
    | where TimeGenerated > ago(Lookback)
    | where OfficeWorkload =~ "SharePoint"
    | where Operation has_any (dynamic(["FileDownloaded", "FileSyncDownloadedFull", "FileAccessed"]))
    | summarize DownloadCount = count(),
                Files = make_set(SourceFileName, 50),
                Sites = make_set(Site_Url, 20),
                DownloadIPs = make_set(ClientIP, 20)
        by UserId, bin(TimeGenerated, 15m);
let AIAccess =
    DeviceNetworkEvents
    | where Timestamp > ago(Lookback)
    | extend RemoteUrl_l = tolower(RemoteUrl),
             AccountUpn = tostring(InitiatingProcessAccountUpn)
    | where isnotempty(RemoteUrl_l) and RemoteUrl_l has_any (AIDomains)
    | where isnotempty(AccountUpn)
    | summarize AIConnections = count(),
                Domains = make_set(RemoteUrl, 25),
                Processes = make_set(InitiatingProcessFileName, 20)
        by UserId = AccountUpn, DeviceName, bin(Timestamp, 15m);
SharePointDownloads
| join kind=innerunique (
    AIAccess
) on UserId
| where Timestamp between (TimeGenerated .. TimeGenerated + CorrelationWindow)
| project DownloadTime = TimeGenerated, UserId, DownloadCount, Files, Sites, DownloadIPs, AIAccessTime = Timestamp, AIConnections, Domains, Processes, DeviceName
| sort by DownloadTime desc

