// ------------------------------------------------------------
// 12. FULL KILL-CHAIN CORRELATION (HIGH FIDELITY)
//     Links the AD RCE exploitation chain on a single DC
//     within 2 hours:
//       (a) High-volume RPC connections (port 135 + dynamic)
//       (b) Unexpected child process from lsass/ntdsa
//       (c) Credential access or AD database theft
//     Three-stage correlation — very low false positive rate.
// ------------------------------------------------------------
let Stage1_RPC =
    DeviceNetworkEvents
    | where Timestamp > ago(14d)
    | where RemotePort in (135, 593)
        or RemotePort between (49152 .. 65535)
    | where InitiatingProcessFileName !in~ (
        "svchost.exe", "lsass.exe", "dns.exe",
        "MsMpEng.exe", "MsSense.exe"
    )
    | summarize RPCBurst = count(),
                DistinctPorts = dcount(RemotePort)
            by DeviceName, RemoteIP, bin(Timestamp, 10m)
    | where RPCBurst > 50 and DistinctPorts > 5
    | project DeviceName, SourceDevice = DeviceName,
              DCIP = RemoteIP, RPCTime = Timestamp, RPCBurst;

let Stage2_Exec =
    DeviceProcessEvents
    | where Timestamp > ago(14d)
    | where InitiatingProcessFileName in~ (
        "lsass.exe", "ntdsa.exe",
        "Microsoft.ActiveDirectory.WebServices.exe"
    )
    | where FileName in~ (
        "cmd.exe", "powershell.exe", "pwsh.exe",
        "rundll32.exe", "net.exe", "whoami.exe",
        "certutil.exe", "bitsadmin.exe", "wmic.exe",
        "nltest.exe"
    )
    | project DeviceName, ExecTime = Timestamp,
              ParentProcess = InitiatingProcessFileName,
              ChildProcess = FileName,
              ExecCmd = ProcessCommandLine;

let Stage3_CredTheft =
    DeviceProcessEvents
    | where Timestamp > ago(14d)
    | where ProcessCommandLine has_any (
        "sekurlsa", "logonpasswords", "dcsync",
        "lsadump", "ntds.dit", "ntdsutil",
        "MiniDump", "comsvcs",
        "vssadmin create shadow",
        "procdump -ma lsass"
    )
    | project DeviceName, TheftTime = Timestamp,
              TheftTool = FileName,
              TheftCmd = ProcessCommandLine;

Stage2_Exec
| join kind=leftouter Stage1_RPC on DeviceName
| where datetime_diff('minute', ExecTime, RPCTime) between (-10 .. 120)
    or isempty(RPCTime)
| join kind=leftouter Stage3_CredTheft on DeviceName
| where datetime_diff('minute', TheftTime, ExecTime) between (0 .. 120)
    or isempty(TheftTime)
| project DeviceName, RPCTime, RPCBurst,
          ExecTime, ParentProcess, ChildProcess, ExecCmd,
          TheftTime, TheftTool, TheftCmd
| sort by ExecTime desc

