// Title: APT28 Kill Chain LNK to UNC to SMB
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1566.001, T1557.001 | CVE-2026-32202
// KQL Library - https://github.com/sivolko/kql-hunter
let timeframe = 7d;
let InitialAccess_LNK = DeviceProcessEvents | where TimeGenerated > ago(timeframe)
    | where InitiatingProcessCommandLine has ".lnk"
    | project DeviceId, LNK_TriggerTime = TimeGenerated, LNK_CommandLine = InitiatingProcessCommandLine;
let Execution_UNC = DeviceProcessEvents | where TimeGenerated > ago(timeframe)
    | where ProcessCommandLine matches regex @"\\\\[a-zA-Z0-9\-\.]{4,}\\\\"
    | where ProcessCommandLine has_any (".cpl", ".dll", ".exe")
    | project DeviceId, UNC_LoadTime = TimeGenerated, UNC_CommandLine = ProcessCommandLine;
let Exfiltration_SMB = DeviceNetworkEvents | where TimeGenerated > ago(timeframe)
    | where RemotePort == 445 | where not(ipv4_is_private(RemoteIP))
    | project DeviceId, SMB_ConnectTime = TimeGenerated, RemoteIP;
InitialAccess_LNK
| join kind=inner Execution_UNC on DeviceId
| where UNC_LoadTime between (LNK_TriggerTime .. (LNK_TriggerTime + 2m))
| join kind=inner Exfiltration_SMB on DeviceId
| where SMB_ConnectTime between (UNC_LoadTime .. (UNC_LoadTime + 2m))
| project DeviceId, LNK_Time = LNK_TriggerTime, UNC_Time = UNC_LoadTime, SMB_Time = SMB_ConnectTime, LNK_CommandLine, UNC_CommandLine, RemoteIP
| extend AlertTitle = "APT28 Kill Chain: LNK->UNC->SMB", Severity = "Critical", MITRE = "T1566.001->T1557.001"

