// Title: Git Abuse High Fidelity
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
let GitConfig = DeviceProcessEvents
    | where ProcessCommandLine has "git config --local" | where ProcessCommandLine has_any ("user.name", "user.email")
    | project DeviceId, DeviceName, AccountName, GitConfigTime = Timestamp, GitConfigCmd = ProcessCommandLine;
let GitAmend = DeviceProcessEvents
    | where ProcessCommandLine has "git commit" | where ProcessCommandLine has "--amend"
    | project DeviceId, AmendTime = Timestamp, AmendCmd = ProcessCommandLine;
let GitPush = DeviceProcessEvents
    | where ProcessCommandLine has "git push" | where ProcessCommandLine has_any ("-f", "--force", "-uf", "--force-with-lease")
    | project DeviceId, PushTime = Timestamp, PushCmd = ProcessCommandLine;
let TimeChange = DeviceProcessEvents
    | where FileName in~ ("cmd.exe", "powershell.exe") | where ProcessCommandLine has_any ("date ", "time ", "Set-Date")
    | project DeviceId, TimeChangeTime = Timestamp, TimeChangeCmd = ProcessCommandLine;
GitConfig | join kind=inner GitAmend on DeviceId | join kind=inner GitPush on DeviceId | join kind=leftouter TimeChange on DeviceId
| where AmendTime between (GitConfigTime .. GitConfigTime + 30m)
| where PushTime between (AmendTime .. AmendTime + 30m)
| where isempty(TimeChangeTime) or TimeChangeTime between (GitConfigTime - 15m .. PushTime + 15m)
| project DeviceName, AccountName, GitConfigTime, GitConfigCmd, AmendTime, AmendCmd, PushTime, PushCmd, TimeChangeTime, TimeChangeCmd
| order by PushTime desc

// Title: Privileged RDP Session Source Mismatch
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1078, T1021.001
// KQL Library - https://github.com/sivolko/kql-hunter
let PrivUserPattern = @"sys[ae]\.[a-z]+";
let ExcludedDomains = dynamic(["nt service","font driver host","window manager","nt authority"]);
let DetectionWindow = 1h; let LookbackWindow = 1d;
let DeviceIPs = DeviceNetworkEvents | where Timestamp > ago(LookbackWindow) | where isnotempty(DeviceName) | where LocalIP != "0.0.0.0"
    | project DeviceIP_Timestamp = Timestamp, DeviceName, LocalIP;
let PrivLogons = DeviceLogonEvents | where Timestamp > ago(DetectionWindow) | where LogonType == "RemoteInteractive"
    | where AccountName matches regex PrivUserPattern | where isnotempty(RemoteIP)
    | project-rename PrivAccountName = AccountName, LogonTimestamp = Timestamp;
PrivLogons
| join kind=inner DeviceIPs on $left.RemoteIP == $right.LocalIP
| extend TimeDiff = abs(datetime_diff('second', LogonTimestamp, DeviceIP_Timestamp))
| where TimeDiff < 3600
| summarize arg_min(TimeDiff, *) by LogonTimestamp, DeviceName, PrivAccountName, RemoteIP
| join kind=leftouter (DeviceLogonEvents | where Timestamp > ago(LookbackWindow) | where LogonType in ("Interactive","RemoteInteractive")
    | where AccountDomain !in (ExcludedDomains) | summarize RecentUsers = make_set(AccountName, 3) by DeviceName) on $left.DeviceName1 == $right.DeviceName
| where isnotempty(RecentUsers)
| mv-expand RecentUser = RecentUsers to typeof(string)
| extend Short1 = extract(@"\.(.+)$", 1, PrivAccountName)
| extend Short2 = strcat(substring(RecentUser,0,1), extract(@"\.(.+)$",1,RecentUser))
| summarize MatchFound = countif(Short2 has Short1), arg_max(LogonTimestamp,*) by DeviceName1, PrivAccountName
| where MatchFound == 0
| project LogonTimestamp, DeviceName, PrivAccountName, RemoteIP, RecentUsers

